STEEL_BTO_EXTENDED_PATTERN = r'(?::green_alert:|:greencheckmark:)?\s*([A-Za-z]+)\s*[|]\s*[$]?([0-9.]+)\s+([0-9.]+)\s+([A-Za-z]{3})\s+([0-9]+)(?:ST|ND|RD|TH)?'

# Simple STC pattern: SYMBOL PRICE OUT (no prefix)
