WAXUI_PROFIT_LADDER_PATTERN = r'(\d+\.?\d*)\s*[-–]\s*(\d+\.?\d*)\s*[✓✔️☑✅]?\s*(\d+)%'
WAXUI_HOLDING_PATTERN = r'[Hh]olding\s+(most|majority|1/2|half|runners\s+only|runners|last\s+con[s]?\.?)'
