BISHOP_TRIM_PATTERN = r'[Tt]rimming\s+(?:\?\w\s+)?([A-Za-z]+)\s+(\d+(?:\.\d+)?)\s*([CPcp])\s+(\d{1,2})/(\d{1,2})(?:\s*[\|\n]\s*[*]{0,2}Value:?[*]{0,2})?\s*@\s*\$?(\d+\.?\d*)(%)?'

