STACK_OPT_PATTERN = r'(BTO|STC)\s+(?:(\d+)\s+)?\$?([A-Za-z]+)\s+(\d+(?:\.\d+)?)([CPcp])\s+(\d{1,2})/(\d{1,2})\s*@\s*(\d+\.?\d*)'

