        # Try JC format: BTO $QQQ $627c 12/10 .77
        m = JC_OPT_REGEX.search(text.strip())
        if m:
            use_jc_format = True
            print(f"[Discord] ✓ Matched JC format (strike+type combined)")
        else:
            # Try alternate format: 🟢**BTO $RKT | 21.2 C JAN/16 .56**
            m = ALT_OPT_REGEX.search(text.strip())
