                                                                new_avg_m = re.search(r'[Nn]ew\s+[Aa]vg[.,]?\s+(?:is\s+)?(\d+\.?\d*)', text.strip())
                                                                new_avg = float(new_avg_m.group(1)) if new_avg_m else add_price
