    async def _prewarm_account_caches(self):
        """Pre-warm account data into BrokerHealthMonitor cache for all connected brokers.
        Eliminates 1s+ cache miss on the first order after startup."""
        import asyncio
        try:
            from src.services.broker_health_monitor import get_health_monitor
            hm = get_health_monitor()
            
            brokers_to_warm = []
            if self.broker and (getattr(self.broker, '_logged_in', False) or getattr(self.broker, 'wb', None)):
                brokers_to_warm.append(('WEBULL', self.broker))
            if self.schwab_broker and getattr(self.schwab_broker, 'connected', False):
                brokers_to_warm.append(('SCHWAB', self.schwab_broker))
            if self.paper_broker and getattr(self.paper_broker, 'connected', False):
                brokers_to_warm.append(('ALPACA_PAPER', self.paper_broker))
            if self.robinhood_broker and getattr(self.robinhood_broker, 'connected', False):
                brokers_to_warm.append(('ROBINHOOD', self.robinhood_broker))
            
            warmed = 0
            for broker_name, broker_instance in brokers_to_warm:
                try:
                    account_info = await asyncio.wait_for(broker_instance.get_account_info(), timeout=10)
                    if account_info:
                        hm.update_broker_status(broker_name, True, account_info=account_info)
                        bp = account_info.get('buying_power', 0) or account_info.get('options_buying_power', 0)
                        _original_print(f"[PREWARM] ✓ {broker_name} account cached (BP=${float(bp or 0):,.2f})")
                        warmed += 1
                except Exception as e:
                    _original_print(f"[PREWARM] ⚠️ {broker_name} account pre-warm failed: {e}")
            
            _original_print(f"[PREWARM] 🔥 Account caches pre-warmed for {warmed}/{len(brokers_to_warm)} brokers")
        except Exception as e:
            _original_print(f"[PREWARM] ⚠️ Account pre-warm error: {e}")

    async def _sod_balance_scheduler(self):
        """Capture balance snapshots at startup, daily at 4:00 AM ET (pre-market), and 9:30 AM ET (market open)."""
        import asyncio
        from datetime import datetime, timezone, timedelta

        _original_print("[SOD] Waiting 3 minutes for brokers to stabilize before initial capture...")
        await asyncio.sleep(180)

        try:
            from zoneinfo import ZoneInfo
        except ImportError:
            from backports.zoneinfo import ZoneInfo
        et_tz = ZoneInfo('America/New_York')

        try:
            from src.services.sod_balance_cache import get_sod_cache
            sod = get_sod_cache()
            now_et = datetime.now(et_tz)
            hour_et = now_et.hour
            minute_et = now_et.minute

            _any_broker_name = None
            for _ba in ['broker', 'schwab_broker', 'tastytrade_broker', 'paper_broker', 'robinhood_broker', 'ibkr_broker']:
                _bi = getattr(self, _ba, None)
                if _bi and hasattr(_bi, 'name'):
                    _any_broker_name = _bi.name
                    break

            _pm_exists = sod.is_captured_today(_any_broker_name, snapshot_type="pre_market") if _any_broker_name else False
            _sod_exists = sod.is_captured_today(_any_broker_name, snapshot_type="start_of_day") if _any_broker_name else False

            if hour_et >= 4 and not _pm_exists:
                _original_print("[SOD] Bot started after 4 AM ET and no pre-market snapshot found — capturing now (this uses CURRENT balance, not 4 AM)...")
                await sod.capture_all_brokers(self, snapshot_type="pre_market")
            elif hour_et >= 4 and _pm_exists:
                _original_print(f"[SOD] ✓ Pre-market snapshot already exists from disk — using persisted 4 AM values")

            if (hour_et > 9 or (hour_et == 9 and minute_et >= 30)) and not _sod_exists:
                _original_print("[SOD] Bot started after 9:30 AM ET and no SOD snapshot found — capturing now (this uses CURRENT balance, not 9:30 AM)...")
                await sod.capture_all_brokers(self, snapshot_type="start_of_day")
            elif (hour_et > 9 or (hour_et == 9 and minute_et >= 30)) and _sod_exists:
                _original_print(f"[SOD] ✓ Start-of-day snapshot already exists from disk — using persisted 9:30 AM values")
        except Exception as e:
            _original_print(f"[SOD] Initial capture failed: {e}")

        while True:
            try:
                now_et = datetime.now(et_tz)

                today_4am = now_et.replace(hour=4, minute=0, second=0, microsecond=0)
                today_930am = now_et.replace(hour=9, minute=30, second=0, microsecond=0)
                tomorrow_4am = (now_et + timedelta(days=1)).replace(hour=4, minute=0, second=0, microsecond=0)

                upcoming = []
                if now_et < today_4am:
                    upcoming.append(('pre_market', today_4am))
                if now_et < today_930am:
                    upcoming.append(('start_of_day', today_930am))
                upcoming.append(('pre_market', tomorrow_4am))

                next_type, next_target = upcoming[0]
                wait_seconds = (next_target - now_et).total_seconds()
                if wait_seconds < 1:
                    wait_seconds = 60

                label = "4:00 AM ET (pre-market)" if next_type == "pre_market" else "9:30 AM ET (market open)"
                _original_print(f"[SOD] Next capture: {label} ({wait_seconds/3600:.1f}h from now)")
                await asyncio.sleep(wait_seconds)

                from src.services.sod_balance_cache import get_sod_cache
                sod = get_sod_cache()
                sod.clear(snapshot_type=next_type)

                if next_type == "pre_market":
                    _original_print("[SOD] Daily 4:00 AM ET — capturing pre-market balances...")
                    await sod.capture_all_brokers(self, snapshot_type="pre_market", force=True)
                else:
                    _original_print("[SOD] Daily 9:30 AM ET — capturing start-of-day balances...")
                    await sod.capture_all_brokers(self, snapshot_type="start_of_day", force=True)

            except asyncio.CancelledError:
                break
            except Exception as e:
                _original_print(f"[SOD] Scheduler error: {e}")
                await asyncio.sleep(3600)

