                                    if spy_signal.gain_percent <= 25:
                                        exit_qty = max(1, exit_qty // 4)  # 25% at 25% gain
                                    elif spy_signal.gain_percent <= 50:
                                        exit_qty = max(1, exit_qty // 3)  # ~33%
