                    reason_str = f" ({', '.join(update_reason)})" if update_reason else ""
                    
                    print(f"[DEDUPE] ⚠️ Update detected for {ticker} @ {entry_price} (instance #{existing_instance['id']}, update #{existing_instance['update_count'] + 1}){reason_str}")
